require 'spikard'
require 'json'
require 'faraday'

RSpec.describe 'request_id' do
  let(:base_url) { ENV.fetch('TEST_SERVER_URL', 'http://localhost:8080') }
  let(:client) do
    Faraday.new(url: base_url) do |f|
      f.request :json
      f.response :json, content_type: /\bjson$/
    end
  end

  describe 'GET /request-id/preserved' do
    it 'When the client supplies X-Request-ID the same value should appear on the response.' do
      response = client.get('/request-id/preserved',
        headers: { 'X-Request-ID' => 'trace-123' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'echo' => 'trace-123', 'status' => 'preserved' })
      expect(response.headers['x-request-id']).to eq('trace-123')
    end
  end

  describe 'GET /request-id/generated' do
    it 'Ensures the request ID middleware attaches a UUID to responses when the client does not send one.' do
      response = client.get('/request-id/generated')
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'status' => 'generated' })
      expect(response.headers['x-request-id']).to match(/\A[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\z/i)
    end
  end

  describe 'GET /request-id/disabled' do
    it 'When request ID generation is disabled the response should not contain X-Request-ID even if the client sends a header.' do
      response = client.get('/request-id/disabled',
        headers: { 'X-Request-ID' => 'external-id' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'status' => 'no-request-id' })
      expect(response.headers['x-request-id']).to be_nil
    end
  end
end
